import React, { useState } from 'react';
import { itemAPI } from '../services/api';

const ApiTest = () => {
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);

  const testApi = async () => {
    setLoading(true);
    setResult('Testing...');

    try {
      console.log('Testing API call...');
      console.log('API Base URL:', process.env.REACT_APP_API_URL || 'http://localhost:8080/api');

      const testData = {
        title: 'Test Item from Component',
        description: 'Testing from React component',
        category: 'Electronics',
        location: 'Test Location',
        type: 'LOST'
      };

      console.log('Sending data:', testData);

      const response = await itemAPI.add(testData);

      console.log('API Response:', response);
      setResult(`Success! Item added with ID: ${response.data.id}`);
    } catch (error) {
      console.error('API Error:', error);
      setResult(`Error: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container mt-4">
      <h3>API Test Component</h3>
      <button 
        onClick={testApi} 
        disabled={loading}
        className="btn btn-primary"
      >
        {loading ? 'Testing...' : 'Test Add Item API'}
      </button>
      <div className="mt-3">
        <strong>Result:</strong>
        <pre className="alert alert-info">{result}</pre>
      </div>
    </div>
  );
};

export default ApiTest;
